record Quote(String symbol, double price, long timestamp) {}
record WatchReq(String symbol, int count) {}

// Test helper: captures streaming output
class TestStreamObserver<T> implements StreamObserver<T> {
    final List<T> received = new ArrayList<>();
    Throwable error;
    boolean completed;
    @Override public void onNext(T v) { received.add(v); }
    @Override public void onError(Throwable t) { error = t; }
    @Override public void onCompleted() { completed = true; }
}

@GrpcService
class QuoteStreamService {
    public void watchPrices(WatchReq req, StreamObserver<Quote> obs) {
        double basePrice = 2800.0;
        for (int i = 0; i < req.count(); i++) {
            // In real impl: check isCancelled() and build from market data
            obs.onNext(new Quote(req.symbol(), basePrice + i * 0.5, System.nanoTime()));
        }
        obs.onCompleted();
    }
}

