import io.grpc.stub.StreamObserver;
import net.devh.boot.grpc.server.service.GrpcService;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.concurrent.atomic.*;

record TradeRecord(String symbol, long amountPaise, boolean valid) {}
record UploadSummary(int totalTrades, long totalValuePaise, int errorCount) {}

@GrpcService
class BatchTradeService {
    // Returns StreamObserver that receives client's stream of TradeRecords
    public StreamObserver<TradeRecord> uploadTrades(
            StreamObserver<UploadSummary> responseObserver) {

        AtomicInteger count = new AtomicInteger(0);
        AtomicLong totalValue = new AtomicLong(0);
        AtomicInteger errors = new AtomicInteger(0);

        return new StreamObserver<TradeRecord>() {
            @Override
            public void onNext(TradeRecord trade) {
                // Accumulate as each trade arrives:
                count.incrementAndGet();
                if (trade.valid()) {
                    totalValue.addAndGet(trade.amountPaise());
                } else {
                    errors.incrementAndGet();
                }
            }
            @Override
            public void onError(Throwable t) {
                responseObserver.onError(t);
            }
            @Override
            public void onCompleted() {
                // Client done sending — now send the single summary response:
                UploadSummary summary = new UploadSummary(
                    count.get(), totalValue.get(), errors.get());
                responseObserver.onNext(summary);
                responseObserver.onCompleted();
            }
        };
    }
}

@SpringBootTest
class ClientStreamingTest {
    @Autowired BatchTradeService svc;

    @Test void threeTrades_correctSummary() {
        TestStreamObserver<UploadSummary> resultObs = new TestStreamObserver<>();
        StreamObserver<TradeRecord> sender = svc.uploadTrades(resultObs);

        sender.onNext(new TradeRecord("RELIANCE", 28000_00L, true));   // ₹28,000
        sender.onNext(new TradeRecord("TCS", 35000_00L, true));        // ₹35,000
        sender.onNext(new TradeRecord("INFY", 0L, false));             // invalid
        sender.onCompleted(); // signal done sending

        assertEquals(3, resultObs.received.get(0).totalTrades());
        assertEquals(63000_00L, resultObs.received.get(0).totalValuePaise());
        assertEquals(1, resultObs.received.get(0).errorCount());
        assertTrue(resultObs.completed);
    }
    @Test void emptyStream_zeroSummary() {
        TestStreamObserver<UploadSummary> resultObs = new TestStreamObserver<>();
        StreamObserver<TradeRecord> sender = svc.uploadTrades(resultObs);
        sender.onCompleted(); // immediately done
        assertEquals(0, resultObs.received.get(0).totalTrades());
    }
}

