import java.time.Instant;

record EchoRequest(String message) {}
record EchoResponse(String message, String processedAt) {}

@GrpcService
class EchoBidiService {
    // Returns StreamObserver for client requests;
    // uses responseObserver to send back responses:
    public StreamObserver<EchoRequest> echo(
            StreamObserver<EchoResponse> responseObserver) {

        return new StreamObserver<EchoRequest>() {
            @Override
            public void onNext(EchoRequest req) {
                // Echo immediately for each request:
                responseObserver.onNext(new EchoResponse(
                    req.message(),
                    Instant.now().toString()));
            }
            @Override
            public void onError(Throwable t) { responseObserver.onError(t); }
            @Override
            public void onCompleted() {
                responseObserver.onCompleted(); // mirror client completion
            }
        };
    }
}

@SpringBootTest
class BidiStreamingTest {
    @Autowired EchoBidiService svc;

    @Test void echo_respondsToEachMessage() {
        TestStreamObserver<EchoResponse> responses = new TestStreamObserver<>();
        StreamObserver<EchoRequest> sender = svc.echo(responses);

        sender.onNext(new EchoRequest("Hello HDFC"));
        sender.onNext(new EchoRequest("Hello Zerodha"));
        sender.onCompleted();

        assertEquals(2, responses.received.size());
        assertEquals("Hello HDFC", responses.received.get(0).message());
        assertEquals("Hello Zerodha", responses.received.get(1).message());
        assertTrue(responses.completed);
    }
    @Test void echo_procesedAt_isSet() {
        TestStreamObserver<EchoResponse> responses = new TestStreamObserver<>();
        StreamObserver<EchoRequest> sender = svc.echo(responses);
        sender.onNext(new EchoRequest("test"));
        sender.onCompleted();
        assertNotNull(responses.received.get(0).processedAt());
    }
}

import io.grpc.stub.*;
import net.devh.boot.grpc.server.service.GrpcService;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@GrpcService
class MarketSubscriptionService {
    private final Map<String, StreamObserver<Quote>> subscriptions = new ConcurrentHashMap<>();

    public void watchSymbol(WatchReq req, StreamObserver<Quote> obs) {
        String key = req.symbol() + "-" + System.nanoTime();

        // Cast to get cancel handler support:
        ServerCallStreamObserver<Quote> serverObs =
            (ServerCallStreamObserver<Quote>) obs;

        // Register cancel handler — CRITICAL for cleanup:
        serverObs.setOnCancelHandler(() -> {
            subscriptions.remove(key);
            // In production: also unsubscribe from market data feed
        });

        // Add subscription:
        subscriptions.put(key, obs);

        // Send a few quotes (simulating real-time feed):
        for (int i = 0; i < 3 && !serverObs.isCancelled(); i++) {
            obs.onNext(new Quote(req.symbol(), 2800.0 + i, System.nanoTime()));
        }
        // For real infinite streams: don't call onCompleted()
        // For this finite test: call it
        obs.onCompleted();
        subscriptions.remove(key);
    }

    public int activeSubscriptions() { return subscriptions.size(); }

    // Broadcast to all subscribers of a symbol:
    public void broadcast(String symbol, Quote quote) {
        subscriptions.entrySet().stream()
            .filter(e -> e.getKey().startsWith(symbol))
            .forEach(e -> e.getValue().onNext(quote));
    }
}

@SpringBootTest
class SubscriptionTest {
    @Autowired MarketSubscriptionService svc;

    @Test void subscription_removedAfterStream() {
        TestStreamObserver<Quote> obs = new TestStreamObserver<>();
        svc.watchSymbol(new WatchReq("RELIANCE", 3), obs);
        // After onCompleted: subscription removed
        assertEquals(0, svc.activeSubscriptions());
        assertEquals(3, obs.received.size());
    }
    @Test void isCancelled_stopsStream() {
        // A non-cast StreamObserver: isCancelled not available — simulate with count
        TestStreamObserver<Quote> obs = new TestStreamObserver<>();
        svc.watchSymbol(new WatchReq("TCS", 2), obs);
        assertEquals(2, obs.received.size()); // only 2 quotes sent
    }
}

