import java.util.Random;
import java.util.Map;

record PriceFeedReq(String symbol, int quoteCount) {}
record NseQuote(String symbol, double price, double changePercent) {}

@GrpcService
class ZerodhaPriceFeed {
    private final Random random = new Random();
    private static final Map<String, Double> BASE_PRICES = Map.of(
        "RELIANCE", 2800.0, "TCS", 3500.0, "INFY", 1600.0, "HDFC", 1500.0
    );

    public void watchPrices(PriceFeedReq req, StreamObserver<NseQuote> obs) {
        ServerCallStreamObserver<NseQuote> sobs = (ServerCallStreamObserver<NseQuote>) obs;
        sobs.setOnCancelHandler(() -> { /* cleanup subscription */ });

        double base = BASE_PRICES.getOrDefault(req.symbol(), 1000.0);
        double lastPrice = base;

        for (int i = 0; i < req.quoteCount() && !sobs.isCancelled(); i++) {
            // Random walk: ±0.5% of last price
            double change = (random.nextDouble() - 0.5) * 0.01 * lastPrice;
            lastPrice += change;
            double changePct = (lastPrice - base) / base * 100;

            obs.onNext(new NseQuote(req.symbol(), lastPrice, changePct));
        }
        obs.onCompleted();
    }
}

@SpringBootTest
class PriceFeedTest {
    @Autowired ZerodhaPriceFeed feed;

    @Test void quotesCount_correct() {
        TestStreamObserver<NseQuote> obs = new TestStreamObserver<>();
        feed.watchPrices(new PriceFeedReq("RELIANCE", 10), obs);
        assertEquals(10, obs.received.size());
        assertTrue(obs.completed);
    }
    @Test void prices_nearBase() {
        TestStreamObserver<NseQuote> obs = new TestStreamObserver<>();
        feed.watchPrices(new PriceFeedReq("TCS", 5), obs);
        // All prices within ±10% of base (3500):
        obs.received.forEach(q -> {
            assertTrue(q.price() > 3150 && q.price() < 3850,
                "Price should be near 3500: " + q.price());
        });
    }
    @Test void unknownSymbol_defaultBase() {
        TestStreamObserver<NseQuote> obs = new TestStreamObserver<>();
        feed.watchPrices(new PriceFeedReq("UNKNOWN-XYZ", 3), obs);
        assertEquals(3, obs.received.size());
        obs.received.forEach(q -> assertTrue(q.price() > 0));
    }
}

