record PaymentInstruction(String merchantId, long amountPaise, String upiId) {}
record BatchResult(int total, int processed, int failed, long totalValuePaise) {}

@GrpcService
class BatchPaymentService {
    public StreamObserver<PaymentInstruction> uploadPayments(
            StreamObserver<BatchResult> responseObserver) {

        AtomicInteger total = new AtomicInteger();
        AtomicInteger processed = new AtomicInteger();
        AtomicInteger failed = new AtomicInteger();
        AtomicLong totalValue = new AtomicLong();

        return new StreamObserver<PaymentInstruction>() {
            @Override
            public void onNext(PaymentInstruction p) {
                total.incrementAndGet();
                if (p.amountPaise() <= 0 || p.upiId() == null || p.upiId().isBlank()) {
                    failed.incrementAndGet();
                } else {
                    processed.incrementAndGet();
                    totalValue.addAndGet(p.amountPaise());
                }
            }
            @Override
            public void onError(Throwable t) { responseObserver.onError(t); }
            @Override
            public void onCompleted() {
                responseObserver.onNext(new BatchResult(
                    total.get(), processed.get(), failed.get(), totalValue.get()));
                responseObserver.onCompleted();
            }
        };
    }
}

