        sender.onNext(new PaymentInstruction("M1", 50000L, "user@okaxis"));
        sender.onNext(new PaymentInstruction("M2", 75000L, "another@upi"));
        sender.onNext(new PaymentInstruction("M3", 0L, "bad@upi"));      // invalid: amount=0
        sender.onNext(new PaymentInstruction("M4", 25000L, ""));           // invalid: blank upi
        sender.onNext(new PaymentInstruction("M5", 100000L, "third@ybl"));
        sender.onCompleted();

        BatchResult r = result.received.get(0);
