import io.grpc.stub.StreamObserver;
import net.devh.boot.grpc.server.service.GrpcService;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.ConcurrentSkipListMap;

record OrderRequest(String side, String symbol, long price, int qty) {}
record BookUpdate(String symbol, long bestBid, long bestAsk, int bidDepth, int askDepth) {}

@GrpcService
class OrderBookService {
    // Price → quantity maps (thread-safe sorted maps):
    private final ConcurrentSkipListMap<Long, Integer> bids = new ConcurrentSkipListMap<>(Comparator.reverseOrder());
    private final ConcurrentSkipListMap<Long, Integer> asks = new ConcurrentSkipListMap<>();

    public StreamObserver<OrderRequest> liveOrderBook(
            StreamObserver<BookUpdate> responseObserver) {

        return new StreamObserver<OrderRequest>() {
            @Override
            public void onNext(OrderRequest order) {
                // Update book:
                if ("BUY".equals(order.side())) {
                    bids.merge(order.price(), order.qty(), Integer::sum);
                } else {
                    asks.merge(order.price(), order.qty(), Integer::sum);
                }

                // Send current book state:
                BookUpdate update = new BookUpdate(
                    order.symbol(),
                    bids.isEmpty() ? 0 : bids.firstKey(),
                    asks.isEmpty() ? 0 : asks.firstKey(),
                    bids.values().stream().mapToInt(Integer::intValue).sum(),
                    asks.values().stream().mapToInt(Integer::intValue).sum()
                );
                responseObserver.onNext(update);
            }
            @Override
            public void onError(Throwable t) { responseObserver.onError(t); }
            @Override
            public void onCompleted() { responseObserver.onCompleted(); }
        };
    }

    public void reset() { bids.clear(); asks.clear(); }
}

@SpringBootTest
class OrderBookTest {
    @Autowired OrderBookService svc;

    @BeforeEach void reset() { svc.reset(); }

    @Test void buyOrder_updatesBestBid() {
        TestStreamObserver<BookUpdate> updates = new TestStreamObserver<>();
        StreamObserver<OrderRequest> sender = svc.liveOrderBook(updates);

        sender.onNext(new OrderRequest("BUY", "RELIANCE", 2800_00L, 100));
        sender.onCompleted();

        assertEquals(1, updates.received.size());
        assertEquals(2800_00L, updates.received.get(0).bestBid());
        assertEquals(100, updates.received.get(0).bidDepth());
    }
    @Test void bidAsk_spread_computed() {
        TestStreamObserver<BookUpdate> updates = new TestStreamObserver<>();
        StreamObserver<OrderRequest> sender = svc.liveOrderBook(updates);
        sender.onNext(new OrderRequest("BUY", "TCS", 3500_00L, 50));
        sender.onNext(new OrderRequest("SELL", "TCS", 3505_00L, 30));
        sender.onCompleted();

        BookUpdate last = updates.received.get(1);
        assertEquals(3500_00L, last.bestBid());
        assertEquals(3505_00L, last.bestAsk());
    }
}

