@Service
class SymbolRegistry {
    private final Map<String,Set<String>> subs = new ConcurrentHashMap<>();
    void add(String symbol, String clientId){subs.computeIfAbsent(symbol,k->new HashSet<>()).add(clientId);}
    void remove(String symbol, String clientId){if(subs.containsKey(symbol)) subs.get(symbol).remove(clientId);}
    int subscriptionCount(String symbol){return subs.getOrDefault(symbol,Set.of()).size();}
    int totalActiveClients(){return subs.values().stream().mapToInt(Set::size).sum();}
    void clear(){subs.clear();}
}

@GrpcService
class ZerodhaMarketStreamer {
    private final SymbolRegistry registry;
    private final AtomicLong totalStreamed = new AtomicLong(0);

    ZerodhaMarketStreamer(SymbolRegistry r){registry=r;}

    public void watchPrices(PriceFeedReq req, StreamObserver<NseQuote> obs){
        if(req.symbol()==null||req.symbol().isBlank()){
            obs.onError(Status.INVALID_ARGUMENT.withDescription("symbol required").asRuntimeException()); return;
        }
        ServerCallStreamObserver<NseQuote> sobs=(ServerCallStreamObserver<NseQuote>)obs;
        String clientId="client-"+System.nanoTime();
        registry.add(req.symbol(),clientId);
        sobs.setOnCancelHandler(()->registry.remove(req.symbol(),clientId));

        double base=2800.0; double last=base;
        Random rng=new Random();
        for(int i=0;i<req.quoteCount()&&!sobs.isCancelled();i++){
            last+=rng.nextGaussian()*2.0;
            obs.onNext(new NseQuote(req.symbol(),last,((last-base)/base)*100));
            totalStreamed.incrementAndGet();
        }
        obs.onCompleted();
        registry.remove(req.symbol(),clientId);
    }
    long getTotalStreamed(){return totalStreamed.get();}
}

@SpringBootTest
class ZerodhaStreamingFullTest {
    @Autowired ZerodhaMarketStreamer streamer;
    @Autowired SymbolRegistry registry;
    @BeforeEach void reset(){registry.clear(); }

    @Test void stream_correctCount(){
        TestStreamObserver<NseQuote> obs=new TestStreamObserver<>();
        streamer.watchPrices(new PriceFeedReq("RELIANCE",5),obs);
