import io.grpc.stub.StreamObserver;
import io.grpc.Status;
import net.devh.boot.grpc.server.service.GrpcService;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.*;

record PayoutInstruction(String merchantId, long amountPaise, String upiId) {}
record PayoutBatchResult(int total, int succeeded, List<String> failedIds) {}

@GrpcService
class RazorpayBulkPayoutService {
    public StreamObserver<PayoutInstruction> processBulkPayout(
            StreamObserver<PayoutBatchResult> responseObserver) {

        AtomicInteger total=new AtomicInteger();
        AtomicInteger succeeded=new AtomicInteger();
        List<String> failedIds=new ArrayList<>();
        AtomicBoolean fatalError=new AtomicBoolean(false);

        return new StreamObserver<>(){
            @Override public void onNext(PayoutInstruction inst){
                if(fatalError.get()) return; // stop processing after fatal error
                // Fatal: null merchantId = data corruption
                if(inst.merchantId()==null){
                    fatalError.set(true);
                    responseObserver.onError(Status.DATA_LOSS
                        .withDescription("Null merchantId: data corruption")
                        .asRuntimeException());
                    return;
                }
                total.incrementAndGet();
                // Non-fatal: invalid amount
                if(inst.amountPaise()<=0||inst.upiId()==null||inst.upiId().isBlank()){
                    failedIds.add(inst.merchantId());
                } else {
                    succeeded.incrementAndGet();
                }
            }
            @Override public void onError(Throwable t){responseObserver.onError(t);}
            @Override public void onCompleted(){
                if(!fatalError.get()){
                    responseObserver.onNext(new PayoutBatchResult(total.get(),succeeded.get(),failedIds));
                    responseObserver.onCompleted();
                }
            }
        };
    }
}

@SpringBootTest
class BulkPayoutTest {
    @Autowired RazorpayBulkPayoutService svc;

    @Test void partialFailures_correctCounts(){
        TestStreamObserver<PayoutBatchResult> result=new TestStreamObserver<>();
        StreamObserver<PayoutInstruction> sender=svc.processBulkPayout(result);
        sender.onNext(new PayoutInstruction("M1",50000L,"a@upi"));
        sender.onNext(new PayoutInstruction("M2",0L,"b@upi")); // invalid amount
        sender.onNext(new PayoutInstruction("M3",30000L,"c@upi"));
        sender.onCompleted();
        PayoutBatchResult r=result.received.get(0);
        assertEquals(3,r.total());assertEquals(2,r.succeeded());assertEquals(1,r.failedIds().size());
    }
    @Test void nullMerchantId_fatalError(){
        TestStreamObserver<PayoutBatchResult> result=new TestStreamObserver<>();
        StreamObserver<PayoutInstruction> sender=svc.processBulkPayout(result);
        sender.onNext(new PayoutInstruction(null,50000L,"x@upi")); // fatal!
        sender.onCompleted();
        assertNotNull(result.error);
        assertEquals(Status.Code.DATA_LOSS,((io.grpc.StatusRuntimeException)result.error).getStatus().getCode());
    }
    @Test void allValid_allSucceeded(){
        TestStreamObserver<PayoutBatchResult> result=new TestStreamObserver<>();
        StreamObserver<PayoutInstruction> sender=svc.processBulkPayout(result);
        sender.onNext(new PayoutInstruction("M1",10000L,"x@upi"));
        sender.onNext(new PayoutInstruction("M2",20000L,"y@upi"));
        sender.onCompleted();
        assertEquals(2,result.received.get(0).succeeded());
    }
}

