import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.*;

record TradeEvent(String type, String symbol, long price, int qty) {} // NEW|CANCEL
record TradeAck(String type, String orderId, String status, long bestBid, long bestAsk) {}

@GrpcService
class LiveTradingBidiService {
    private final ConcurrentSkipListMap<Long,Integer> bids=new ConcurrentSkipListMap<>(Comparator.reverseOrder());
    private final ConcurrentSkipListMap<Long,Integer> asks=new ConcurrentSkipListMap<>();
    private final Map<String,TradeEvent> activeOrders=new ConcurrentHashMap<>();

    public void reset(){bids.clear();asks.clear();activeOrders.clear();}

    public StreamObserver<TradeEvent> liveTrading(
            StreamObserver<TradeAck> responseObserver){
        return new StreamObserver<>(){
            @Override public void onNext(TradeEvent event){
                if(event.symbol()==null||event.symbol().isBlank()){
                    responseObserver.onError(Status.INVALID_ARGUMENT.withDescription("symbol required").asRuntimeException()); return;
                }
                String orderId="ORD-"+System.nanoTime();
                String status;
                if("NEW".equals(event.type())){
                    if("BUY".equals(event.symbol())) bids.merge(event.price(),event.qty(),Integer::sum);
                    else asks.merge(event.price(),event.qty(),Integer::sum);
                    activeOrders.put(orderId,event);
                    status="PLACED";
                } else {
                    activeOrders.remove(orderId); status="CANCELLED";
                }
                responseObserver.onNext(new TradeAck(event.type(),orderId,status,
                    bids.isEmpty()?0:bids.firstKey(),asks.isEmpty()?0:asks.firstKey()));
            }
            @Override public void onError(Throwable t){responseObserver.onError(t);}
            @Override public void onCompleted(){responseObserver.onCompleted();}
        };
    }
}

@SpringBootTest
class BidiTradingTest {
    @Autowired LiveTradingBidiService svc;
    @BeforeEach void reset(){svc.reset();}

    @Test void newOrder_acked(){
        TestStreamObserver<TradeAck> acks=new TestStreamObserver<>();
        StreamObserver<TradeEvent> sender=svc.liveTrading(acks);
        sender.onNext(new TradeEvent("NEW","BUY",2800_00L,100));
        sender.onCompleted();
        assertEquals(1,acks.received.size());
        assertEquals("PLACED",acks.received.get(0).status());
    }
    @Test void cancelOrder_acked(){
        TestStreamObserver<TradeAck> acks=new TestStreamObserver<>();
        StreamObserver<TradeEvent> sender=svc.liveTrading(acks);
        sender.onNext(new TradeEvent("CANCEL","SELL",3500_00L,50));
        sender.onCompleted();
        assertEquals("CANCELLED",acks.received.get(0).status());
    }
    @Test void multipleOrders_multipleAcks(){
        TestStreamObserver<TradeAck> acks=new TestStreamObserver<>();
        StreamObserver<TradeEvent> sender=svc.liveTrading(acks);
        sender.onNext(new TradeEvent("NEW","BUY",2800_00L,10));
        sender.onNext(new TradeEvent("NEW","BUY",2801_00L,20));
        sender.onCompleted();
        assertEquals(2,acks.received.size());
    }
    @Test void blankSymbol_errors(){
        TestStreamObserver<TradeAck> acks=new TestStreamObserver<>();
        StreamObserver<TradeEvent> sender=svc.liveTrading(acks);
        sender.onNext(new TradeEvent("NEW","",2800_00L,10));
        sender.onCompleted();
        assertNotNull(acks.error);
    }
}

import io.grpc.stub.*;
import net.devh.boot.grpc.server.service.GrpcService;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

record StreamItem(int sequenceNumber, String data) {}

@GrpcService
class BackPressureStreamService {
    private AtomicInteger queued=new AtomicInteger();
    private AtomicInteger sent=new AtomicInteger();

    public void streamWithBackPressure(WatchReq req, StreamObserver<StreamItem> obs){
        ServerCallStreamObserver<StreamItem> sobs=(ServerCallStreamObserver<StreamItem>)obs;

        Queue<StreamItem> pendingQueue=new ArrayDeque<>();
        AtomicInteger seq=new AtomicInteger();

        // When client buffer drains: flush pending queue
        sobs.setOnReadyHandler(()->{
            while(sobs.isReady()&&!pendingQueue.isEmpty()){
                sobs.onNext(pendingQueue.poll());
                sent.incrementAndGet();
            }
        });

        // Produce messages:
        for(int i=0;i<req.quoteCount();i++){
            StreamItem item=new StreamItem(seq.incrementAndGet(),"data-"+i);
            if(sobs.isReady()){
                sobs.onNext(item); sent.incrementAndGet();
            } else {
                pendingQueue.add(item); queued.incrementAndGet();
            }
        }
        // Drain any remaining:
        while(!pendingQueue.isEmpty()){
            sobs.onNext(pendingQueue.poll()); sent.incrementAndGet();
        }
        sobs.onCompleted();
    }
    int getQueued(){return queued.get();}
    int getSent(){return sent.get();}
    void reset(){queued.set(0);sent.set(0);}
}

@SpringBootTest
class BackPressureTest {
    @Autowired BackPressureStreamService svc;
    @BeforeEach void reset(){svc.reset();}

    @Test void allMessagesSent(){
        TestStreamObserver<StreamItem> obs=new TestStreamObserver<>();
        svc.streamWithBackPressure(new WatchReq("RELIANCE",5),obs);
        // All 5 messages must be sent (either directly or from queue):
        assertEquals(5,svc.getSent());
        assertTrue(obs.completed);
    }
    @Test void sequenceNumbers_correct(){
        TestStreamObserver<StreamItem> obs=new TestStreamObserver<>();
        svc.streamWithBackPressure(new WatchReq("TCS",3),obs);
        // Sequence numbers 1,2,3:
        List<Integer> seqs=obs.received.stream().map(StreamItem::sequenceNumber).toList();
        assertEquals(List.of(1,2,3),seqs);
    }
}

import io.grpc.stub.*;
import io.grpc.Status;
import net.devh.boot.grpc.server.service.GrpcService;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.*;

record SynthMsg(int seq, String data) {}
record SynthSum(int count, long total) {}

@GrpcService
class T3SynthServer {
    // Server streaming:
    public void serverStream(PriceFeedReq req, StreamObserver<NseQuote> obs){
        ServerCallStreamObserver<NseQuote> sobs=(ServerCallStreamObserver<NseQuote>)obs;
        sobs.setOnCancelHandler(()->{}); // cleanup placeholder
        for(int i=0;i<req.quoteCount()&&!sobs.isCancelled();i++){
            obs.onNext(new NseQuote(req.symbol(),2800.0+i,0));
        }
        obs.onCompleted();
    }
    // Client streaming:
    public StreamObserver<SynthMsg> clientStream(StreamObserver<SynthSum> responseObserver){
        AtomicInteger count=new AtomicInteger();
        AtomicLong total=new AtomicLong();
        return new StreamObserver<>(){
            @Override public void onNext(SynthMsg m){count.incrementAndGet();total.addAndGet(m.seq());}
            @Override public void onError(Throwable t){responseObserver.onError(t);}
            @Override public void onCompleted(){responseObserver.onNext(new SynthSum(count.get(),total.get()));responseObserver.onCompleted();}
        };
    }
    // Bidi streaming:
    public StreamObserver<SynthMsg> bidi(StreamObserver<SynthMsg> responseObserver){
        return new StreamObserver<>(){
            @Override public void onNext(SynthMsg m){responseObserver.onNext(new SynthMsg(m.seq()*2,m.data()+"-echo"));}
            @Override public void onError(Throwable t){responseObserver.onError(t);}
            @Override public void onCompleted(){responseObserver.onCompleted();}
        };
    }
}

@SpringBootTest
class M28T3SynthesisTest {
    @Autowired T3SynthServer svc;

    @Test void serverStreaming_sends3(){
        TestStreamObserver<NseQuote> obs=new TestStreamObserver<>();
        svc.serverStream(new PriceFeedReq("RELIANCE",3),obs);
        assertEquals(3,obs.received.size());assertTrue(obs.completed);
    }
    @Test void clientStreaming_aggregates(){
        TestStreamObserver<SynthSum> result=new TestStreamObserver<>();
        StreamObserver<SynthMsg> sender=svc.clientStream(result);
        sender.onNext(new SynthMsg(1,"a"));sender.onNext(new SynthMsg(2,"b"));sender.onCompleted();
        assertEquals(2,result.received.get(0).count());
        assertEquals(3L,result.received.get(0).total()); // 1+2=3
    }
    @Test void bidiStreaming_echo(){
        TestStreamObserver<SynthMsg> responses=new TestStreamObserver<>();
        StreamObserver<SynthMsg> sender=svc.bidi(responses);
        sender.onNext(new SynthMsg(5,"hello"));
        sender.onCompleted();
        assertEquals(1,responses.received.size());
        assertEquals(10,responses.received.get(0).seq()); // 5*2=10
        assertEquals("hello-echo",responses.received.get(0).data());
    }
    @Test void serverStream_emptySymbol(){
        TestStreamObserver<NseQuote> obs=new TestStreamObserver<>();
        svc.serverStream(new PriceFeedReq("RELIANCE",0),obs); // 0 quotes requested
        assertEquals(0,obs.received.size());assertTrue(obs.completed); // 0 is valid
    }
}
